import{_ as t,o as e,c as i,a2 as s}from"./chunks/framework.M-AdQQii.js";const h=JSON.parse('{"title":"3.2 宗师武器","description":"本节点为目录/结构标题，具体操作内容见其下级章节。 宗师木质武器不管是单双手还是什么类型材料都是一样的，所以这里只使用单手 杖来展示： 一把木质武器需要10 个武器强化卷轴、172 瓶武器源晶精华、1 个阳光庇护（4毒囊、4 甲胄、50 龙","frontmatter":{"title":"3.2 宗师武器","description":"本节点为目录/结构标题，具体操作内容见其下级章节。 宗师木质武器不管是单双手还是什么类型材料都是一样的，所以这里只使用单手 杖来展示： 一把木质武器需要10 个武器强化卷轴、172 瓶武器源晶精华、1 个阳光庇护（4毒囊、4 甲胄、50 龙","outline":"deep"},"headers":[],"relativePath":"grandmaster/3-2.md","filePath":"grandmaster/3-2.md","lastUpdated":null}'),l={name:"grandmaster/3-2.md"};function r(o,a,d,u,p,g){return e(),i("div",null,[...a[0]||(a[0]=[s('<h1 id="_3-2-宗师武器" tabindex="-1">3.2 宗师武器 <a id="s230-d9966e27"></a> <a class="header-anchor" href="#_3-2-宗师武器" aria-label="Permalink to &quot;3.2 宗师武器 &lt;a id=&quot;s230-d9966e27&quot;&gt;&lt;/a&gt;&quot;">​</a></h1><p>本节点为目录/结构标题，具体操作内容见其下级章节。</p><h2 id="_3-2-1-木质武器制作材料展览" tabindex="-1">3.2.1 木质武器制作材料展览 <a id="s231-01cd7d8e"></a> <a class="header-anchor" href="#_3-2-1-木质武器制作材料展览" aria-label="Permalink to &quot;3.2.1 木质武器制作材料展览 &lt;a id=&quot;s231-01cd7d8e&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>宗师木质武器不管是单双手还是什么类型材料都是一样的，所以这里只使用单手</p><p>杖来展示：</p><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2507.jpeg" alt="图示：3.2.1 木质武器制作材料展览" loading="lazy"></figure><h2 id="_3-2-2-木质武器制作材料统计" tabindex="-1">3.2.2 木质武器制作材料统计 <a id="s232-12d14696"></a> <a class="header-anchor" href="#_3-2-2-木质武器制作材料统计" aria-label="Permalink to &quot;3.2.2 木质武器制作材料统计 &lt;a id=&quot;s232-12d14696&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>一把木质武器需要10 个武器强化卷轴、172 瓶武器源晶精华、1 个阳光庇护（4毒囊、4 甲胄、50 龙骨）、132 个源晶锭、153 个亚纳锭、102 根烈火原木、425 个龙骨、17000 个木材、34000 个玉米、34000 个大米、850 个庭院的神秘粉末、5100 个花生、5100 个小麦、3400 个红色珊瑚草、5985 个黑炭。</p><h2 id="_3-2-3-铁质武器制作材料展览" tabindex="-1">3.2.3 铁质武器制作材料展览 <a id="s233-7f51bde6"></a> <a class="header-anchor" href="#_3-2-3-铁质武器制作材料展览" aria-label="Permalink to &quot;3.2.3 铁质武器制作材料展览 &lt;a id=&quot;s233-7f51bde6&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>宗师铁质武器不管是单双手还是什么类型材料都是一样的，所以这里只使用匕首</p><p>来展示：</p><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2516.jpeg" alt="图示：3.2.3 铁质武器制作材料展览" loading="lazy"></figure><h2 id="_3-2-4-铁质武器制作材料统计" tabindex="-1">3.2.4 铁质武器制作材料统计 <a id="s234-cb376f31"></a> <a class="header-anchor" href="#_3-2-4-铁质武器制作材料统计" aria-label="Permalink to &quot;3.2.4 铁质武器制作材料统计 &lt;a id=&quot;s234-cb376f31&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>一把铁质武器需要10 个武器强化卷轴、172 瓶武器源晶精华、1 个阳光庇护（4毒囊、4 甲胄、50 龙骨）、132 个源晶锭、153 个亚纳锭、102 根烈火原木、425 个龙骨、13600 个铁锭、1700 个铜锭、1700 个银锭、34000 个映山红、34000 个水仙花、</p><p>850 个庭院的神秘粉末、5100 个莲花、5100 个燕麦、3400 个鹿角杯型珊瑚草、5985个黑炭。</p><h2 id="_3-2-5-宗师武器推荐制作方式" tabindex="-1">3.2.5 宗师武器推荐制作方式 <a id="s235-f99fe020"></a> <a class="header-anchor" href="#_3-2-5-宗师武器推荐制作方式" aria-label="Permalink to &quot;3.2.5 宗师武器推荐制作方式 &lt;a id=&quot;s235-f99fe020&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>推荐制作木质武器再用点券买转换券转成铁质武器。</p><p>上图6000 点券的神赐级别转换券即为宗师武器类型转换券。</p><p>注意：单手武器只能转成单手武器，双手武器只能转成双手武器，解放后的是下面那个12000 点券的，所以建议做出来就转换。</p><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2524.jpeg" alt="图示：3.2.5 宗师武器推荐制作方式" loading="lazy"></figure><h2 id="_3-2-6-宗师盾牌制作展览" tabindex="-1">3.2.6 宗师盾牌制作展览 <a id="s236-c4a1c9cc"></a> <a class="header-anchor" href="#_3-2-6-宗师盾牌制作展览" aria-label="Permalink to &quot;3.2.6 宗师盾牌制作展览 &lt;a id=&quot;s236-c4a1c9cc&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>本节点为目录/结构标题，具体操作内容见其下级章节。</p><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_2529.jpeg" alt="图示：3.2.6 宗师盾牌制作展览" loading="lazy"></figure><h2 id="_3-2-7-宗师盾牌制作材料统计" tabindex="-1">3.2.7 宗师盾牌制作材料统计 <a id="s237-f63f2544"></a> <a class="header-anchor" href="#_3-2-7-宗师盾牌制作材料统计" aria-label="Permalink to &quot;3.2.7 宗师盾牌制作材料统计 &lt;a id=&quot;s237-f63f2544&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>一把盾牌需要10 个武器强化卷轴、172 瓶武器源晶精华、1 个阳光庇护（4 毒囊、</p><p>4 甲胄、50 龙骨）、132 个源晶锭、153 个亚纳锭、102 根烈火原木、425 个龙骨、</p><p>17000 个木材、34000 个玉米、34000 个大米、850 个庭院的神秘粉末、5100 个花生、</p><p>5100 个小麦、3400 个红色珊瑚草、5985 个黑炭。</p>',28)])])}const n=t(l,[["render",r]]);export{h as __pageData,n as default};
